//! Cross-runtime HELIX parity test (Rust half).
//!
//! Mirrors the workload spec in
//! `foil-runtime/cross-runtime-test/workload.ts`. The TS half exercises
//! the canonical `@a0n/helix` algebra and the foil-runtime reference;
//! this test exercises the canonical `gnosis_helix` algebra. Both halves
//! must agree on the per-task `seesGreen` audit at the assigned slot
//! ticks; the Lean source guarantees the algebra is unique up to
//! byte-equivalence, so any divergence is a SSOT violation.

use gnosis_helix::{
    corridor_all_green, earliest_green_start, sees_green, Stoplight,
};

// Mirror of `PARITY_WORKLOAD` in
// `foil-runtime/cross-runtime-test/workload.ts`. Any change here MUST
// be mirrored there (and vice versa) — these are the canonical parity
// fixtures the SSOT contract is verified against.
const TASK_COUNT: u32 = 50;
const BOTTLENECK_MS: u32 = 8;
const CYCLE_MS: u32 = TASK_COUNT * BOTTLENECK_MS; // 400

/// Build the per-task Stoplight assignment, exactly matching
/// `makeParityLights()` in `workload.ts`.
fn make_parity_lights() -> Vec<Stoplight> {
    let mut out = Vec::with_capacity(TASK_COUNT as usize);
    for i in 0..TASK_COUNT {
        let raw = (CYCLE_MS as i64 - ((i as i64) * BOTTLENECK_MS as i64) % CYCLE_MS as i64)
            .rem_euclid(CYCLE_MS as i64);
        let offset = raw as u32;
        out.push(Stoplight::new(CYCLE_MS, BOTTLENECK_MS, offset, 0, 1));
    }
    out
}

#[test]
fn parity_workload_every_task_green_at_its_own_slot() {
    let lights = make_parity_lights();
    for (i, light) in lights.iter().enumerate() {
        let tick = (i as u32) * BOTTLENECK_MS;
        assert!(
            sees_green(tick, *light),
            "task {i} must be green at tick {tick} (TS-half pinned this too)",
        );
    }
}

#[test]
fn parity_workload_earliest_green_start_equals_slot_tick() {
    let lights = make_parity_lights();
    for (i, light) in lights.iter().enumerate() {
        let expected = (i as u32) * BOTTLENECK_MS;
        assert_eq!(
            earliest_green_start(*light),
            expected,
            "task {i} earliest green start should be {expected}",
        );
    }
}

#[test]
fn parity_workload_only_one_task_per_green_tick() {
    let lights = make_parity_lights();
    for tick in 0..CYCLE_MS {
        let hits = lights.iter().filter(|l| sees_green(tick, **l)).count();
        assert!(
            hits <= 1,
            "tick {tick} had {hits} concurrent green tasks (expected ≤ 1)",
        );
    }
}

#[test]
fn parity_workload_full_cycle_coverage() {
    let lights = make_parity_lights();
    let mut total_green_ticks: u32 = 0;
    for tick in 0..CYCLE_MS {
        for l in &lights {
            if sees_green(tick, *l) {
                total_green_ticks += 1;
            }
        }
    }
    assert_eq!(
        total_green_ticks,
        TASK_COUNT * BOTTLENECK_MS,
        "green coverage must equal N*green",
    );
}

#[test]
fn parity_workload_corridor_all_green_when_we_pick_a_legal_tick() {
    // corridorAllGreen on the parity workload only holds at tick 0 for
    // a single-task corridor — by design tasks pre-empt each other.
    // The witness here: if we restrict to just task 0's light, tick 0
    // is all-green; for the full 50-light corridor, no single tick is
    // all-green (which is the desired property — staggering, not
    // simultaneous admission).
    let lights = make_parity_lights();
    assert!(corridor_all_green(0, &lights[0..1]));
    let any_all_green = (0..CYCLE_MS).any(|t| corridor_all_green(t, &lights));
    assert!(!any_all_green, "no tick should be green at ALL 50 lights");
}
